<?php
class Person {
    public $name;       // anyone can access
    protected $age;     // accessible in Person and child classes
    private $ssn;       // only inside Person

    public function __construct($name, $age, $ssn) {
        $this->name = $name;
        $this->age = $age;
        $this->ssn = $ssn;
    }

    protected function getAge() {
        return $this->age;
    }

    private function getSsn() {
        return $this->ssn;
    }
}

class Employee extends Person {
    public function display() {
        echo $this->name;      // OK
        echo $this->getAge();  // OK (protected)
        // echo $this->ssn;    // Error: private
        // echo $this->getSsn(); // Error: private
    }
}

